  /**
   * Generate search URL for full archive search
   * @param {string} query - Search term
   * @returns {string} URL to navigate to
   */
  searchFullArchive: function(query) {
    const baseUrl = 'https://www.derstandard.at/search';
    const params = new URLSearchParams({
      query: query,
      fd: '1997-01-01',
      s: 'score',
      n: ''
    });
    return `${baseUrl}?${params.toString()}`;
  },

  /**
   * Extract search results from current page and append to search-results.json
   * Creates artifact if it doesn't exist, appends if it does
   * @returns {Promise<object>} Status with count of articles extracted
   */
  extractSearchResults: async function() {
    const articles = Array.from(document.querySelectorAll('article[data-type="story"]'));

    const extractedArticles = articles.map(article => {
      const header = article.querySelector('header');
      const linkEl = article.querySelector('a[data-story-id]');

      if (!header || !linkEl) return null;

      const title = header.querySelector('.teaser-title')?.textContent?.trim() || null;
      const link = linkEl.href;
      const dateEl = header.querySelector('dst-rl-timestamp');
      const date = dateEl ? dateEl.getAttribute('date') : null;
      const kicker = header.querySelector('.teaser-kicker')?.textContent?.trim() || null;
      const subtitle = header.querySelector('.teaser-subtitle')?.textContent?.trim() || null;

      return { title, link, date, kicker, teaser: subtitle, content: null };
    }).filter(article => article !== null);

    // Get or create artifact
    const files = await listArtifacts();
    let data;

    if (files.includes('search-results.json')) {
      data = await getArtifact('search-results.json');
      data.articles.push(...extractedArticles);
      data.totalArticles = data.articles.length;
    } else {
      // Extract query from URL
      const urlParams = new URLSearchParams(window.location.search);
      const query = urlParams.get('query') || 'unknown';

      data = {
        query: query,
        totalArticles: extractedArticles.length,
        articles: extractedArticles
      };
    }

    await createOrUpdateArtifact('search-results.json', data);

    return {
      extractedCount: extractedArticles.length,
      totalCount: data.totalArticles,
      message: `Extracted ${extractedArticles.length} articles, total now ${data.totalArticles}`
    };
  },

  /**
   * Get pagination information from current search results page
   * @returns {object} Pagination info
   */
  getPaginationInfo: function() {
    const paginationContainer = document.querySelector('.pagination');

    if (!paginationContainer) {
      return { hasMore: false, nextPageUrl: null, currentPage: 1, totalPages: 1 };
    }

    const pageText = paginationContainer.textContent;
    const pageMatch = pageText.match(/Seite\s+(\d+)\s+von\s+(\d+)/);

    let currentPage = 1;
    let totalPages = 1;

    if (pageMatch) {
      currentPage = parseInt(pageMatch[1]);
      totalPages = parseInt(pageMatch[2]);
    }

    const nextLink = paginationContainer.querySelector('a[href*="&p="]');
    const nextPageUrl = nextLink ? nextLink.href : null;

    return {
      hasMore: currentPage < totalPages,
      nextPageUrl,
      currentPage,
      totalPages
    };
  },

  /**
   * Extract article content from current article page and update search-results.json
   * Finds matching article by URL and adds content
   * @returns {Promise<object>} Status
   */
  extractArticleContent: async function() {
    const currentUrl = window.location.href;

    // Extract article content
    const titleEl = document.querySelector('h1');
    const title = titleEl ? titleEl.textContent.trim() : null;

    const dateEl = document.querySelector('dst-rl-timestamp, time[datetime]');
    const date = dateEl ? (dateEl.getAttribute('date') || dateEl.getAttribute('datetime')) : null;

    const authorEl = document.querySelector('[class*="author"], .byline, [rel="author"]');
    const author = authorEl ? authorEl.textContent.trim() : null;

    const paragraphs = Array.from(document.querySelectorAll('.article-body > p'))
      .map(p => p.textContent.trim())
      .filter(text => text.length > 20);

    const content = paragraphs.join('\n\n');

    // Update artifact
    const data = await getArtifact('search-results.json');

    // Find article by URL
    const article = data.articles.find(a => a.link === currentUrl);

    if (article) {
      article.content = content;
      if (author) article.author = author;
      await createOrUpdateArtifact('search-results.json', data);

      return {
        success: true,
        title: article.title,
        contentLength: content.length,
        message: `Updated article content for: ${article.title}`
      };
    } else {
      return {
        success: false,
        message: 'Article not found in search results. URL: ' + currentUrl
      };
    }
  }
};"
